"""Shared helpers used by both sessions.py and processes.py.

Promoted here so the dependency graph is explicit: both peer modules
depend inward on _helpers, instead of processes.py reaching across to
sessions.py for what are really package-internal building blocks.

The leading underscore on the filename marks the module as internal to
the queries package — nothing here is re-exported via __init__.py.
"""

import aiosqlite

from agentpulse.api.v2.state import derive_state


async def latest_hook_for_session(
    db: aiosqlite.Connection, *, session_id: str
) -> dict | None:
    cursor = await db.execute(
        """
        SELECT * FROM claude_log_hooks
        WHERE session_id = ?
        ORDER BY received_at DESC, id DESC LIMIT 1
        """,
        (session_id,),
    )
    row = await cursor.fetchone()
    return dict(row) if row else None


_NON_STATE_EVENTS: frozenset[str] = frozenset(
    {
        "Notification",
        "SessionEnd",
    }
)


async def latest_root_hook_for_session(
    db: aiosqlite.Connection, *, session_id: str
) -> dict | None:
    """Latest state-producing hook from the root agent (agent_id IS NULL).

    Skips Notification and SessionEnd — events that derive_state maps to
    None — so the session state reflects the last meaningful root action.
    """
    placeholders = ",".join("?" for _ in _NON_STATE_EVENTS)
    cursor = await db.execute(
        f"""
        SELECT * FROM claude_log_hooks
        WHERE session_id = ? AND agent_id IS NULL
              AND event_name NOT IN ({placeholders})
        ORDER BY received_at DESC, id DESC LIMIT 1
        """,
        (session_id, *_NON_STATE_EVENTS),
    )
    row = await cursor.fetchone()
    return dict(row) if row else None


async def agents_for_session(
    db: aiosqlite.Connection, *, session_id: str
) -> list[dict]:
    """Build agent projections for a session.

    One row per distinct agent_id seen in claude_log_hooks. agent_type comes
    from the introducing event (the row that first carried a non-null
    agent_type). last_event/last_tool/last_event_at come from the latest row
    for that agent_id.
    """
    cursor = await db.execute(
        """
        SELECT DISTINCT agent_id FROM claude_log_hooks
        WHERE session_id = ? AND agent_id IS NOT NULL
        """,
        (session_id,),
    )
    agent_ids = [r["agent_id"] for r in await cursor.fetchall()]

    agents: list[dict] = []
    for aid in agent_ids:
        # Type: first non-null agent_type for this agent
        cursor = await db.execute(
            """
            SELECT agent_type FROM claude_log_hooks
            WHERE agent_id = ? AND agent_type IS NOT NULL
            ORDER BY received_at, id LIMIT 1
            """,
            (aid,),
        )
        type_row = await cursor.fetchone()
        agent_type = type_row["agent_type"] if type_row else None

        # First / latest events
        cursor = await db.execute(
            """
            SELECT MIN(received_at) AS started_at,
                   MAX(received_at) AS last_event_at
            FROM claude_log_hooks
            WHERE agent_id = ?
            """,
            (aid,),
        )
        win_row = await cursor.fetchone()
        win = dict(win_row) if win_row else {}

        cursor = await db.execute(
            """
            SELECT event_name, tool_name FROM claude_log_hooks
            WHERE agent_id = ?
            ORDER BY received_at DESC, id DESC LIMIT 1
            """,
            (aid,),
        )
        latest_row = await cursor.fetchone()
        if latest_row is None:
            continue
        latest = dict(latest_row)

        ended_at = (
            win["last_event_at"] if latest["event_name"] == "SubagentStop" else None
        )
        derived = derive_state(
            latest["event_name"], tool_name=latest["tool_name"] or "", agent_id=aid
        )

        agents.append(
            {
                "agent_id": aid,
                "session_id": session_id,
                "agent_type": agent_type,
                "started_at": win["started_at"],
                "ended_at": ended_at,
                "last_event": latest["event_name"],
                "last_tool": latest["tool_name"],
                "last_event_at": win["last_event_at"],
                "derived_state": derived,
            }
        )
    return agents


def active_agent_states(agents: list[dict]) -> list[str | None]:
    """Filter to states of agents that haven't terminated."""
    return [a["derived_state"] for a in agents if a["ended_at"] is None]
